var MEM0_BASE2 = "https://api.mem0.ai/v1";
var MEM0_API_KEY2 = process.env.MEM0_API_KEY || "";
var AGENT_ID = "behzod_agent_core";
var LESSON_CACHE_TTL_MS = 60000;
var cachedLessons = "";
var cachedLessonsFetchedAt = 0;
function mem0Headers2() {
  return {
    "Content-Type": "application/json",
    Authorization: `Token ${MEM0_API_KEY2}`
  };
}
async function getAgentLessons() {
  if (cachedLessonsFetchedAt && Date.now() - cachedLessonsFetchedAt < LESSON_CACHE_TTL_MS) {
    return cachedLessons;
  }
  try {
    const res = await fetch(`${MEM0_BASE2}/memories/?user_id=${AGENT_ID}`, {
      method: "GET",
      headers: mem0Headers2()
    });
    const data = await res.json();
    const memories = Array.isArray(data) ? data : data.results || [];
    if (memories.length === 0) {
      cachedLessons = "No past behavior lessons stored yet.";
      cachedLessonsFetchedAt = Date.now();
      return cachedLessons;
    }
    cachedLessons = memories.map((m) => `- ${m.memory || m.content || ""}`).join(`
`);
    cachedLessonsFetchedAt = Date.now();
    return cachedLessons;
  } catch (e) {
    Logger.error("Failed to fetch agent lessons from Mem0", e);
    return cachedLessons;
  }
}
var saveAgentLesson = tool(async ({ lesson }) => {
  Logger.tool("save_agent_lesson", lesson, "START");
  try {
    const res = await fetch(`${MEM0_BASE2}/memories/`, {
      method: "POST",
      headers: mem0Headers2(),
      body: JSON.stringify({
        messages: [{ role: "user", content: `BEHAVIOR RULE: ${lesson}` }],
        user_id: AGENT_ID
      })
    });
    if (!res.ok)
      return "Failed to save the lesson.";
    cachedLessonsFetchedAt = 0;
    Logger.tool("save_agent_lesson", lesson, "DONE");
    return `Succesfully saved new behavior lesson: "${lesson}"`;
  } catch (e) {
    Logger.tool("save_agent_lesson", lesson, "ERROR", e.message);
    return "Error saving lesson.";
  }
}, {
  name: "save_agent_lesson",
  description: "Store a new behavioral lesson or correction so the agent remembers not to make the same mistake again (e.g., 'Never mention session IDs' or 'Always use bullets for steps').",
  schema: exports_external4.object({
    lesson: exports_external4.string().describe("The specific rule or correction to remember.")
  })
});

// src/composio.ts
var TRELLO_API_KEY = process.env.TRELLO_API_KEY || "";
var TRELLO_TOKEN = process.env.TRELLO_TOKEN || "";
var TRELLO_LIST_ID = process.env.TRELLO_LIST_ID || "";
function isSimilar(query, target) {
  const q = query.toLowerCase().split(/\s+/).filter((w) => w.length > 3);
  const t2 = target.toLowerCase();
  const matches = q.filter((word) => t2.includes(word));
  return matches.length / q.length > TRELLO_CONFIG.SIMILARITY_THRESHOLD;
}
async function getExistingCards() {
  const url3 = `https://api.trello.com/1/lists/${TRELLO_LIST_ID}/cards?key=${TRELLO_API_KEY}&token=${TRELLO_TOKEN}&fields=name,desc,shortUrl,idList`;
  const res = await fetch(url3);
  if (!res.ok)
    return [];
  return await res.json();
}
async function searchCards(query) {
  const encodedQuery = encodeURIComponent(query);
  const url3 = `https://api.trello.com/1/search?key=${TRELLO_API_KEY}&token=${TRELLO_TOKEN}&query=${encodedQuery}&modelTypes=cards&card_fields=name,desc,shortUrl,idList&cards_limit=15`;
  const res = await fetch(url3);
  if (!res.ok)
    return [];
  const data = await res.json();
  return Array.isArray(data?.cards) ? data.cards : [];
}
async function addCommentToCard(cardId, text) {
  const url3 = `https://api.trello.com/1/cards/${cardId}/actions/comments?key=${TRELLO_API_KEY}&token=${TRELLO_TOKEN}`;
  await fetch(url3, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text: `\u2795 [NEW REPORT]: ${text}` })
  });
}
var createTrelloCard = tool(async ({ name, description, userId }) => {
  Logger.tool("trello_sync", name, "START");
  if (!TRELLO_API_KEY || !TRELLO_TOKEN || !TRELLO_LIST_ID) {
    return "Trello not configured properly.";
  }
  try {
    const existing = await getExistingCards();
    const duplicate = existing.find((c) => isSimilar(name, c.name));
    if (duplicate) {
      Logger.tool("trello_sync", name, "DONE", `Duplicate clustered to: ${duplicate.shortUrl}`);
      let newDesc = duplicate.desc;
      const reportersTag = /\[REPORTERS: ([\d,\s]+)\]/;
      const match = newDesc.match(reportersTag);
      if (match && userId) {
        const IDs = match[1].split(",").map((id) => id.trim());
        if (!IDs.includes(userId)) {
          newDesc = newDesc.replace(reportersTag, `[REPORTERS: ${match[1]}, ${userId}]`);
          await fetch(`https://api.trello.com/1/cards/${duplicate.id}?key=${TRELLO_API_KEY}&token=${TRELLO_TOKEN}`, {
            method: "PUT",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ desc: newDesc })
          });
        }
      }
      await addCommentToCard(duplicate.id, description);
      return `I found a matching issue already in our system! I've added your report to the existing card so the engineers see the priority increase.
Card: ${duplicate.shortUrl}`;
    }
    const url3 = `https://api.trello.com/1/cards?key=${TRELLO_API_KEY}&token=${TRELLO_TOKEN}`;
    const finalDesc = `${description}

[REPORTERS: ${userId || "unknown"}]`;
    const res = await fetch(url3, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        idList: TRELLO_LIST_ID,
        name,
        desc: finalDesc,
        pos: "top"
      })
    });
    const data = await res.json();
    if (!res.ok)
      throw new Error(data?.message || "Trello Error");
    Logger.tool("trello_sync", name, "DONE", `New unique issue recorded: ${data.shortUrl}`);
    return `New issue recorded successfully!
URL: ${data.shortUrl}`;
  } catch (e) {
    Logger.tool("trello_sync", name, "ERROR", e.message);
    return `Error: ${e.message}`;
  }
}, {
  name: "create_trello_card",
  description: "Create or cluster a Trello issue with detailed, structured information. IMPORTANT: Only call this after gathering complete details about the issue (what, where, when, error message, expected behavior, user goal). The description should be comprehensive and well-formatted.",
  schema: exports_external4.object({
    name: exports_external4.string().describe("Concise title in English (e.g., 'Login button not working on admin panel')"),
    description: exports_external4.string().describe("Detailed structured description with sections: Problem, Location, Timing, Error, Expected Result, User Goal, and Reporter Info. Use the template format with emojis and clear sections."),
    userId: exports_external4.string().optional().describe("The Telegram user ID of the reporter")
  })
});
var getIssueStatus = tool(async ({ query }) => {
  Logger.tool("get_issue_status", query, "START");
  try {
    const [cardsFromList, cardsFromSearch] = await Promise.all([
      getExistingCards(),
      searchCards(query)
    ]);
    const cards = [...cardsFromList, ...cardsFromSearch].filter((card, index2, items) => items.findIndex((item) => item.id === card.id) === index2);
    const found = cards.find((c) => isSimilar(query, c.name) || c.desc.includes(query));
    if (!found)
      return "I couldn't find a matching issue in the active list.";
    const listUrl = `https://api.trello.com/1/lists/${found.idList}?key=${TRELLO_API_KEY}&token=${TRELLO_TOKEN}`;
    const listRes = await fetch(listUrl);
    const listData = await listRes.json();
    const status2 = listData.name || "Unknown";
    Logger.tool("get_issue_status", query, "DONE", `Status: ${status2}`);
    return `Found issue: "${found.name}"
Status: [${status2.toUpperCase()}]
URL: ${found.shortUrl}`;
  } catch (e) {
    return `Error: ${e.message}`;
  }
}, {
  name: "get_issue_status",
  description: "Check the progress of a previously reported issue by searching for keywords or card titles.",
  schema: exports_external4.object({
    query: exports_external4.string().describe("The issue title or key details to search for")
  })
});

