// src/reply-sanitizer.ts
var INTERNAL_TOOL_PATTERN = /\b(search_company|get_user_profile|save_user_info|search_user_memory|search_recent_memories|delete_memory|get_all_memories|save_agent_lesson|create_trello_card|get_issue_status|search_memory)\b/i;
var HARD_BLOCK_PATTERNS = [
  /##\s*Core Rules/i,
  /##\s*Issue Reporting Process/i,
  /##\s*Learned Lessons/i,
  /\[REPORTERS:[^\]]*\]/i,
  /\bmessageModifier\b/i,
  /\bcheckpoint[_ -]?id\b/i,
  INTERNAL_TOOL_PATTERN
];
var SAFE_FALLBACK_REPLY = "Uzr, ichki tizim ma'lumotlarini ko'rsatmasligim kerak. Savolni qayta yozing. / \u0418\u0437\u0432\u0438\u043D\u0438\u0442\u0435, \u044F \u043D\u0435 \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0442\u044C \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0435 \u0434\u0430\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B. \u041F\u043E\u0432\u0442\u043E\u0440\u0438\u0442\u0435 \u0432\u043E\u043F\u0440\u043E\u0441.";
function sanitizeAgentReply(text) {
  if (!text) {
    return "";
  }
  let cleaned = String(text).trim();
  cleaned = cleaned.replace(/<function=[^>]*>\{[^}]*\}<\/function>/g, "").trim();
  cleaned = cleaned.replace(/<function=[^>]*>[^<]*(<\/function>)?/g, "").trim();
  cleaned = cleaned.replace(/\[User\s+@[^\]]+\]\s*/gi, "");
  cleaned = cleaned.replace(/\[Web User\s+\(ID:[^)]+\)\]\s*/gi, "");
  cleaned = cleaned.replace(/\b(?:Telegram|Web)\s+ID:\s*[A-Za-z0-9_-]+\b/gi, "");
  cleaned = cleaned.replace(/\bID:(?:telegram|web)_[A-Za-z0-9_-]+\b/gi, "");
  cleaned = cleaned.replace(/\[REPORTERS:[^\]]*\]/gi, "");
  cleaned = cleaned.replace(/\b(?:thread|checkpoint)[ _-]?id\s*:\s*[A-Za-z0-9_-]+\b/gi, "");
  cleaned = cleaned.replace(/\n{3,}/g, `

`).trim();
  if (!cleaned) {
    return "";
  }
  if (HARD_BLOCK_PATTERNS.some((pattern) => pattern.test(cleaned))) {
    return SAFE_FALLBACK_REPLY;
  }
  return cleaned;
}

// src/web-chat.ts
var webSessions = new Map;
var SESSION_TTL_MINUTES2 = 30;
function normalizeWebUserId(userId) {
  return userId.startsWith("web_") ? userId : `web_${userId}`;
}
function getWebSession(userId) {
  const normalizedUserId = normalizeWebUserId(userId);
  const now = new Date;
  let session = webSessions.get(normalizedUserId);
  if (session) {
    const minutesSinceLastActivity = (now.getTime() - session.lastActivityAt.getTime()) / 1000 / 60;
    if (minutesSinceLastActivity >= SESSION_TTL_MINUTES2) {
      Logger.info(`Web session expired for ${normalizedUserId}, creating new thread`);
      session = undefined;
    }
  }
  if (!session) {
    session = {
      userId: normalizedUserId,
      threadId: `behzod_${normalizedUserId}_${Date.now()}`,
      lastActivityAt: now
    };
    webSessions.set(normalizedUserId, session);
    Logger.info(`New web session created: ${session.threadId}`);
  } else {
    session.lastActivityAt = now;
  }
  return { threadId: session.threadId };
}
async function handleWebMessage(userId, message) {
  const normalizedUserId = normalizeWebUserId(userId);
  try {
    Logger.info(`Web message from ${normalizedUserId}: ${message}`);
    const { threadId } = getWebSession(normalizedUserId);
    const agent = await createBehzodAgent();
    const result = await agent.invoke({ messages: [new HumanMessage(`[Web User (ID:${normalizedUserId})] ${message}`)] }, { configurable: { thread_id: threadId } });
    const lastMessage = result.messages[result.messages.length - 1];
    const response = typeof lastMessage.content === "string" ? lastMessage.content : JSON.stringify(lastMessage.content);
    const safeResponse = sanitizeAgentReply(response);
    Logger.info(`Web response to ${normalizedUserId}: ${safeResponse.substring(0, 100)}...`);
    return safeResponse;
  } catch (error87) {
    Logger.error(`Web chat error for ${normalizedUserId}: ${error87.message}`);
    return "Kechirasiz, xatolik yuz berdi. Iltimos, qaytadan urinib ko'ring. / \u0418\u0437\u0432\u0438\u043D\u0438\u0442\u0435, \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u043B\u0430 \u043E\u0448\u0438\u0431\u043A\u0430. \u041F\u043E\u0436\u0430\u043B\u0443\u0439\u0441\u0442\u0430, \u043F\u043E\u043F\u0440\u043E\u0431\u0443\u0439\u0442\u0435 \u0441\u043D\u043E\u0432\u0430.";
  }
}

